import React from "react"
import "../styles/card.scss"

export const CardImage = props => {
  const calculateStyle = () => {
    if (props.data.c.width && props.data.c.height) {
      return props.data.c.width > props.data.c.height ? { width: '100%' } : { height: '100%' }
    }
    return { width: '60%' }
  }
  return <div className='card_image'>
    <a href={props.link} aria-label={"Read the whole story about " + props.data.name}>
      <img src={props.data.media} alt={props.data.name + " screen-shot"}
        style={calculateStyle()} />
    </a>
  </div>
}


