import React from "react"
import { CardImage } from "./cardImage"
import { CardHeader } from "./cardHeader"
import { CardLinks } from "./cardLinks"
import { CardText } from "./cardText"
import "../styles/card.scss"

export default class ProjectCard extends React.Component {
  render() {
    let p = this.props.project
    // prefer `p.fields.slug` when available; ensure it is an absolute path
    const rawSlug = (p && p.fields && p.fields.slug) || p.slug || p.name || '';
    const link = rawSlug && rawSlug.startsWith('/') ? rawSlug : rawSlug ? '/' + rawSlug : '/';
    return (
      <div className='col-sm-6 card__' style={{
        height: this.props.h,
      }}>
        <div className='card_body'>
          <CardImage data={{ media: p.media_pre, name: p.name, h: this.props.h, c: this.props.c }}
            link={link} />
          <CardHeader data={{ title: p.name, techs: p.techs }} />
          <CardLinks data={{ date: p.date, git: p.git_link, web: p.web_link, h: this.props.h }} />
          <CardText data={{ text: p.story, h: this.props.h }} link={link} />
        </div>
      </div>
    )
  }
}